-func CopyFromArchive(ctx context.Context, nameOrID string, path string, reader io.Reader, options *CopyOptions) (entities.ContainerCopyFunc, error) {
+type CopyOption interface {
+	CopyWith(*CopyOptions)
+}
+
+type copyWithFn func(options *CopyOptions)
+
+func (f copyWithFn) CopyWith(options *CopyOptions) {
+	f(options)
+}
+
+func WithChown(chown bool) CopyOption {
+	return copyWithFn(func(options *CopyOptions) {
+		options.WithChown(chown)
+	})
+}
+
+func CopyFromArchive(ctx context.Context, nameOrID string, path string, reader io.Reader, options ...CopyOption) (entities.ContainerCopyFunc, error) {
+	var opts *CopyOptions
+
+	if len(options) > 0 {
+		opts = new(CopyOptions)
+		for _, copyOption := range options {
+			copyOption.CopyWith(opts)
+		}
+	}
+
+	return CopyFromArchiveWithOptions(ctx, nameOrID, path, reader, opts)
+}
+
+func CopyFromArchiveWithOptions(ctx context.Context, nameOrID string, path string, reader io.Reader, options *CopyOptions) (entities.ContainerCopyFunc, error) {
+
 	conn, err := bindings.GetClient(ctx)
 	if err != nil {
